import React, { useState } from 'react';
import './Tasks.css';

const Tasks = () => {
  const [taskInput, setTaskInput] = useState('');
  const [tasks, setTasks] = useState([]);

  const addTask = () => {
    if (taskInput.trim() === '') return;
    const newTask = {
      id: Date.now(),
      title: taskInput,
      items: [],
    };
    setTasks([...tasks, newTask]);
    setTaskInput('');
  };

  const addItemToTask = (taskId) => {
    const itemText = prompt('Add sub-task:');
    if (itemText) {
      setTasks(prev =>
        prev.map(task =>
          task.id === taskId
            ? { ...task, items: [...task.items, { text: itemText, checked: false }] }
            : task
        )
      );
    }
  };

  const toggleCheckbox = (taskId, index) => {
    setTasks(prev =>
      prev.map(task =>
        task.id === taskId
          ? {
              ...task,
              items: task.items.map((item, idx) =>
                idx === index ? { ...item, checked: !item.checked } : item
              ),
            }
          : task
      )
    );
  };

  const deleteTask = (taskId) => {
    setTasks(tasks.filter(task => task.id !== taskId));
  };

  const editTaskTitle = (taskId) => {
    const newTitle = prompt('Edit task title:');
    if (newTitle) {
      setTasks(prev =>
        prev.map(task =>
          task.id === taskId ? { ...task, title: newTitle } : task
        )
      );
    }
  };

  return (
    <div className="task-page">
      <div className="task-input-row">
        <input
          type="text"
          value={taskInput}
          onChange={(e) => setTaskInput(e.target.value)}
          placeholder="Add Task ...."
          className="task-input"
        />
        <button onClick={addTask} className="add-btn">Add</button>
      </div>

      <div className="task-cards">
        {tasks.map(task => (
          <div key={task.id} className="task-card">
            <div className="task-header">
              <span className="task-title">{task.title}</span>
              <div className="icons">
                <button onClick={() => addItemToTask(task.id)}>➕</button>
                <button onClick={() => editTaskTitle(task.id)}>✏️</button>
                <button onClick={() => deleteTask(task.id)}>🗑️</button>
              </div>
            </div>
            <ul className="task-items">
              {task.items.map((item, index) => (
                <li key={index}>
                  <input
                    type="checkbox"
                    checked={item.checked}
                    onChange={() => toggleCheckbox(task.id, index)}
                  />
                  <span className={item.checked ? 'checked' : ''}>{item.text}</span>
                </li>
              ))}
            </ul>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Tasks;
